import { getStoreConfig } from '@/auth/api';
import { useEffect, useState } from 'preact/hooks';
import { StoreConfigModel } from '../../data/models';

export const useGetStoreConfigs = () => {
  const [isEmailConfirmationRequired, setIsEmailConfirmationRequired] =
    useState(false);
  const [passwordConfigs, setPasswordConfigs] = useState<{
    minLength: number;
    requiredCharacterClasses: number;
  } | null>(null);
  const [remoteShoppingAssistanceConfigs, setRemoteShoppingAssistanceConfigs] =
    useState<{
      shoppingAssistanceEnabled: boolean;
      shoppingAssistanceCheckboxTitle: string;
      shoppingAssistanceCheckboxTooltip: string;
    } | null>(null);

  const applyStoreConfig = (config: StoreConfigModel) => {
    const {
      minLength,
      requiredCharacterClasses,
      createAccountConfirmation,
      shoppingAssistanceEnabled,
      shoppingAssistanceCheckboxTitle,
      shoppingAssistanceCheckboxTooltip,
    } = config;

    setPasswordConfigs({
      minLength,
      requiredCharacterClasses,
    });

    setIsEmailConfirmationRequired(createAccountConfirmation);

    setRemoteShoppingAssistanceConfigs({
      shoppingAssistanceEnabled,
      shoppingAssistanceCheckboxTitle,
      shoppingAssistanceCheckboxTooltip,
    });
  };

  useEffect(() => {
    const storeConfigString = sessionStorage.getItem('storeConfig');
    let cachedStoreConfig: StoreConfigModel | null = null;

    try {
      cachedStoreConfig = storeConfigString
        ? JSON.parse(storeConfigString)
        : null;
    } catch {
      cachedStoreConfig = null;
    }

    if (cachedStoreConfig) {
      applyStoreConfig(cachedStoreConfig);
      return;
    }

    getStoreConfig().then((response) => {
      if (!response) return;

      sessionStorage.setItem('storeConfig', JSON.stringify(response));
      applyStoreConfig(response);
    });
  }, []);

  return {
    passwordConfigs,
    isEmailConfirmationRequired,
    remoteShoppingAssistanceConfigs,
  };
};
