import { FunctionComponent, JSX } from 'preact';
import { useState } from 'preact/hooks';
import '@/auth/components/RemoteShoppingAssistanceConsent/RemoteShoppingAssistanceConsent.css';
import { classes } from '@adobe-commerce/elsie/lib';
import { Field, Checkbox } from '@adobe-commerce/elsie/components';

export interface RemoteShoppingAssistanceConsentProps {
  label?: string;
  tooltip?: string;
  name?: string;
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
  className?: string;
}

export const RemoteShoppingAssistanceConsent: FunctionComponent<
  RemoteShoppingAssistanceConsentProps
> = ({
  label = '',
  tooltip = '',
  name = 'allowRemoteShoppingAssistance',
  defaultChecked = false,
  onChange,
  className = '',
}) => {
  const [showTooltip, setShowTooltip] = useState(false);
  const [checked, setChecked] = useState(defaultChecked);
  const tooltipId = `${name}-tooltip`;

  const handleChange = ({
    currentTarget,
  }: JSX.TargetedEvent<HTMLInputElement>) => {
    const isChecked = currentTarget.checked;
    setChecked(isChecked);
    onChange?.(isChecked);
  };

  return (
    <div className={classes(['remote-shopping-assistance-consent', className])}>
      <div className="remote-shopping-assistance-consent__wrapper">
        <Field>
          <Checkbox
            name={name}
            value="true"
            placeholder={label}
            label={label}
            checked={checked}
            onChange={handleChange}
          />
        </Field>
        {tooltip ? (
          <div className="remote-shopping-assistance-consent__info-container">
            <button
              type="button"
              className="remote-shopping-assistance-consent__info-icon"
              onMouseEnter={() => setShowTooltip(true)}
              onMouseLeave={() => setShowTooltip(false)}
              onFocusIn={() => setShowTooltip(true)}
              onFocusOut={() => setShowTooltip(false)}
              aria-describedby={showTooltip ? tooltipId : undefined}
              aria-label={tooltip}
            >
              ?
            </button>
            {showTooltip ? (
              <span
                className="remote-shopping-assistance-consent__tooltip"
                id={tooltipId}
                role="tooltip"
              >
                {tooltip}
                <span className="remote-shopping-assistance-consent__tooltip-arrow" />
              </span>
            ) : null}
          </div>
        ) : null}
      </div>
    </div>
  );
};
